import pika
from pika import credentials, connection

# RabbitMQ Connection Parameters
RABBITMQ_HOST = 'localhost'
RABBITMQ_PORT = 5672
RABBITMQ_USERNAME = 'guest'
RABBITMQ_PASSWORD = 'guest'

# Create a connection to the RabbitMQ server
credentials = credentials.PlainCredentials(RABBITMQ_USERNAME, RABBITMQ_PASSWORD)
connection_params = pika.ConnectionParameters(host=RABBITMQ_HOST, port=RABBITMQ_PORT, credentials=credentials)

# Establish a connection to the RabbitMQ server
conn = connection.Connection(parameters=connection_params)

# Create a channel object
channel = conn.channel()

# Declare an exchange and queue for job messages
exchange_name = 'job_exchange'
queue_name = 'job_queue'

channel.exchange_declare(exchange=exchange_name, type='direct')
channel.queue_declare(queue=queue_name)
channel.queue_bind(exchange=exchange_name, queue=queue_name)

def callback(ch, method, properties, msg):
    try:
        # Execute the shell command from the message body
        subprocess.run(msg.body, check=True, shell=True)
    except subprocess.CalledProcessError as e:
        print(f"Error executing job: {e}")
    finally:
        ch.basic_ack(delivery_tag=method.delivery_tag)

# Consume messages from the queue
channel.basic_consume(queue=queue_name,
                      on_message_callback=callback,
                      no_ack=False)

print("Waiting for jobs...")
conn.ioloop.start()